fn solve(nums: Vec<i64>, k: i64) -> i64 {
    if nums.len() == 1 {
        return 0;
    }

    let mut nums_sorted = nums.clone();
    nums_sorted.sort_by(|a, b| a.cmp(b));

    let n = nums_sorted.len();
    let mut min_removals = n as i64; // Max possible removals

    for i in 0..n {
        // Check if the subarray from i to n-1 is balanced
        let max = nums_sorted[n - 1];
        let min = nums_sorted[i];
        if max <= min * k {
            // All elements from i to n-1 are kept, so removals are n - i - 1
            min_removals = std::cmp::min(min_removals, (n - i - 1) as i64);
            break; // Since array is sorted, no need to check further
        }
    }

    min_removals
}
