    if nums.len() == 1 {
        return 0;
    }

    let mut nums = nums;
    nums.sort();

    let n = nums.len();
    let mut min_removals = n - 1; // Worst case: remove all but one

    for i in 0..n {
        // Check if the subarray from i to n-1 is balanced
        let mut max = nums[n - 1];
        let mut min = nums[i];
        for j in i..n {
            if nums[j] > max {
                max = nums[j];
            }
            if nums[j] < min {
                min = nums[j];
            }
            if max > min * k {
                break;
            }
        }

        // If the subarray is balanced, we can keep it and remove the rest
        if max <= min * k {
            min_removals = (n - 1 - i) as i64;
            break;
        }
    }

    min_removals
}
