fn solve(nums: Vec<i64>, k: i64) -> i64 {
    if nums.len() == 1 {
        return 0;
    }

    let mut nums = nums;
    nums.sort_unstable();

    let n = nums.len();
    let mut min_remove = n as i64;

    for i in 0..n {
        let j = n - 1;
        while i < j {
            let max = nums[j];
            let min = nums[i];
            if max <= min * k {
                min_remove = min_remove.min((j - i) as i64);
                break;
            } else {
                j -= 1;
            }
        }
    }

    min_remove
}
